parameters.jsCode:
const job = $('Fetch this job').item.json;
const bu = $('Fetch BU').item.json;
const precedentRaw = $json;
const precedent = Array.isArray(precedentRaw) ? precedentRaw : (Array.isArray(precedentRaw?.body) ? precedentRaw.body : []);

const MAX = 600;
const precedentBlock = precedent.map((p, i) => {
  const cl = p.cover_letter ? '\n' + p.cover_letter.slice(0, MAX) + (p.cover_letter.length > MAX ? '…' : '') : '\n(no text)';
  return `### Precedent ${i+1}: ${p.job_title}` + cl;
}).join('\n\n');

const systemPrompt = [
  'You write professional cover letters for SWL Consulting on Upwork. 300-350 words, English unless job is Spanish. Tone: professional, strategic, direct. Sign with "Juan". No hyphens or em dashes. Output only the cover letter, no preamble.',
  '',
  '## Structure (in this exact order):',
  '1. Welcome greeting (2 sentences, 50-60 words, reference one specific job detail, use "we")',
  '2. Initial hook (empathy + client pain)',
  '3. Authority paragraph: MBA + Master Finance + FMVA from CFI Canada + at least one of Juan\'s roles (Managing Director Latam consulting, Head of Investments LA media fund, CFO European SaaS) with measurable examples. 8-10 lines.',
  '4. 3-5 bullet points starting with action verbs about what we bring',
  '5. SWL intro: boutique advisory firm, 20+ pros, AI-powered solutions in finance/strategy/ops/sales, link one service from BU scope. 5-6 lines.',
  '6. Call to action (one of the 3 standard sentences)',
  '7. Closing line + "Juan" signature',
  '',
  `## SWL Business Unit: ${bu.name || 'unknown'}`,
  bu.description || '',
  `Scopes: ${(bu.scopes || []).join(' · ')}`,
  `Keywords: ${(bu.keywords || []).slice(0, 25).join(', ')}`,
  `Good-fit signals: ${bu.good_fit_signals || ''}`,
  '',
  precedent.length ? `## Recent Sent precedent\n\n${precedentBlock}` : '## Recent Sent precedent\n(none yet)',
].join('\n');

const userPrompt = [
  '## JOB POST',
  `Title: ${job.title}`,
  `Industry: ${job.industry || 'n/a'}`,
  `Client location: ${job.country || 'n/a'}`,
  `Duration: ${job.duration || 'n/a'}`,
  `Hourly rate: $${job.hourly_average}/h`,
  '',
  'Description:',
  job.description || '(no description)',
].join('\n');

return { json: { job_id: job.id, systemPrompt, userPrompt } };

parameters.jsonBody:
={{ JSON.stringify({
  model: "claude-sonnet-4-5",
  max_tokens: 1500,
  system: $json.systemPrompt,
  messages: [ { role: "user", content: $json.userPrompt } ]
}) }}

